#[cfg(test)]
mod tests {
    #![allow(dead_code)]
    #![allow(unused_imports)]

    use super::*;
    use crate::feature::dtos::CreateFeatureDto;
    use crate::feature::feature_controller;
    use crate::root::dtos::CreateRootDto;
    use crate::root::root_controller;
    use crate::use_case::dtos::CreateUseCaseDto;
    use crate::use_case::use_case_controller;
    use crate::workspace::dtos::CreateWorkspaceDto;
    use crate::workspace::workspace_controller;
    use common::database::db_context::DbContext;
    use common::event::EventHub;
    use common::types::EntityId;
    use common::undo_redo::UndoRedoManager;
    use std::sync::Arc;

    struct TestContext {
        db: DbContext,
        hub: Arc<EventHub>,
        undo: UndoRedoManager,
    }

    impl TestContext {
        fn new() -> Self {
            let db = DbContext::new().expect("Failed to create in-memory DB");
            let hub = Arc::new(EventHub::new());
            let mut undo = UndoRedoManager::new();
            undo.set_event_hub(&hub);
            TestContext { db, hub, undo }
        }
    }

    /// Build the ownership chain and return the direct owner's id.
    fn create_owner_chain(ctx: &mut TestContext) -> EntityId {
        let root =
            root_controller::create_orphan(&ctx.db, &ctx.hub, &CreateRootDto::default()).unwrap();
        let workspace = workspace_controller::create(
            &ctx.db,
            &ctx.hub,
            &mut ctx.undo,
            None,
            &CreateWorkspaceDto::default(),
            root.id,
            -1,
        )
        .unwrap();
        let feature = feature_controller::create(
            &ctx.db,
            &ctx.hub,
            &mut ctx.undo,
            None,
            &CreateFeatureDto::default(),
            workspace.id,
            -1,
        )
        .unwrap();
        let use_case = use_case_controller::create(
            &ctx.db,
            &ctx.hub,
            &mut ctx.undo,
            None,
            &CreateUseCaseDto::default(),
            feature.id,
            -1,
        )
        .unwrap();
        use_case.id
    }

    /// Create an entity using create_orphan.
    fn create_one(ctx: &mut TestContext) -> DtoDto {
        create_orphan(
            &ctx.db,
            &ctx.hub,
            &mut ctx.undo,
            None,
            &CreateDtoDto::default(),
        )
        .unwrap()
    }

    // -----------------------------------------------------------------------
    // create_orphan + get
    // -----------------------------------------------------------------------

    #[test]
    fn test_create_orphan_and_get() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        assert!(created.id > 0);

        let fetched = get(&ctx.db, &created.id).unwrap();
        assert!(fetched.is_some());
        assert_eq!(fetched.unwrap().id, created.id);
    }

    // -----------------------------------------------------------------------
    // get nonexistent
    // -----------------------------------------------------------------------

    #[test]
    fn test_get_nonexistent() {
        let ctx = TestContext::new();
        assert!(get(&ctx.db, &999999).unwrap().is_none());
    }

    // -----------------------------------------------------------------------
    // get_all
    // -----------------------------------------------------------------------

    #[test]
    fn test_get_all() {
        let mut ctx = TestContext::new();
        create_one(&mut ctx);
        let all = get_all(&ctx.db).unwrap();
        assert!(!all.is_empty());
    }

    // -----------------------------------------------------------------------
    // get_multi
    // -----------------------------------------------------------------------

    #[test]
    fn test_get_multi() {
        let mut ctx = TestContext::new();
        let a = create_one(&mut ctx);
        let results = get_multi(&ctx.db, &[a.id, 999999]).unwrap();
        assert_eq!(results.len(), 2);
        assert!(results[0].is_some());
        assert!(results[1].is_none());
    }

    // -----------------------------------------------------------------------
    // update
    // -----------------------------------------------------------------------

    #[test]
    fn test_update() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        let update_dto: UpdateDtoDto = created.into();
        let updated = update(&ctx.db, &ctx.hub, &mut ctx.undo, None, &update_dto).unwrap();
        assert_eq!(updated.id, update_dto.id);
    }

    // -----------------------------------------------------------------------
    // remove
    // -----------------------------------------------------------------------

    #[test]
    fn test_remove() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        remove(&ctx.db, &ctx.hub, &mut ctx.undo, None, &created.id).unwrap();
        assert!(get(&ctx.db, &created.id).unwrap().is_none());
    }

    // -----------------------------------------------------------------------
    // remove_multi
    // -----------------------------------------------------------------------

    #[test]
    fn test_remove_multi() {
        let mut ctx = TestContext::new();
        let a = create_one(&mut ctx);
        remove_multi(&ctx.db, &ctx.hub, &mut ctx.undo, None, &[a.id]).unwrap();
        assert!(get(&ctx.db, &a.id).unwrap().is_none());
    }

    // -----------------------------------------------------------------------
    // create with owner
    // -----------------------------------------------------------------------

    #[test]
    fn test_create_with_owner() {
        let mut ctx = TestContext::new();
        let owner_id = create_owner_chain(&mut ctx);
        let created = create(
            &ctx.db,
            &ctx.hub,
            &mut ctx.undo,
            None,
            &CreateDtoDto::default(),
            owner_id,
            -1,
        )
        .unwrap();
        assert!(created.id > 0);
        let fetched = get(&ctx.db, &created.id).unwrap();
        assert!(fetched.is_some());
    }

    // -----------------------------------------------------------------------
    // undo create_orphan
    // -----------------------------------------------------------------------

    #[test]
    fn test_create_orphan_undo() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        assert!(get(&ctx.db, &created.id).unwrap().is_some());
        ctx.undo.undo(None).unwrap();
        assert!(get(&ctx.db, &created.id).unwrap().is_none());
    }

    // -----------------------------------------------------------------------
    // undo remove
    // -----------------------------------------------------------------------

    #[test]
    fn test_remove_undo() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        remove(&ctx.db, &ctx.hub, &mut ctx.undo, None, &created.id).unwrap();
        assert!(get(&ctx.db, &created.id).unwrap().is_none());
        ctx.undo.undo(None).unwrap();
        assert!(get(&ctx.db, &created.id).unwrap().is_some());
    }

    // -----------------------------------------------------------------------
    // relationship: get default
    // -----------------------------------------------------------------------

    #[test]
    fn test_get_relationship_default() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        let rel_ids =
            get_relationship(&ctx.db, &created.id, &DtoRelationshipField::Fields).unwrap();
        assert!(rel_ids.is_empty());
    }

    // -----------------------------------------------------------------------
    // relationship: count default
    // -----------------------------------------------------------------------

    #[test]
    fn test_get_relationship_count_default() {
        let mut ctx = TestContext::new();
        let created = create_one(&mut ctx);
        let count =
            get_relationship_count(&ctx.db, &created.id, &DtoRelationshipField::Fields).unwrap();
        assert_eq!(count, 0);
    }
}
